// Input: Basic LLM Chain Output mit JSON in Markdown
const llmOutput = $input.first().json.text;

// Schritt 1: Bereinige Markdown-Formatierung
let cleanedOutput = llmOutput
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

// Schritt 2: Extrahiere NUR das JSON (ignoriere Text danach!)
const jsonStart = cleanedOutput.indexOf('{');
const jsonEnd = cleanedOutput.lastIndexOf('}');

if (jsonStart === -1 || jsonEnd === -1) {
  throw new Error('Kein JSON gefunden im Output');
}

const jsonString = cleanedOutput.substring(jsonStart, jsonEnd + 1);

// Schritt 3: Parse JSON
let clusterData;
try {
  clusterData = JSON.parse(jsonString);
} catch (error) {
  throw new Error(`JSON Parse Error: ${error.message}\nExtracted JSON: ${jsonString.substring(0, 500)}...`);
}

// Schritt 4: Validierung - KEIN clusters Array mehr!
if (!clusterData.cluster_name || !clusterData.primary_keyword) {
  throw new Error('Cluster-Name oder Primary-Keyword fehlt im JSON');
}

// Schritt 5: Hole Unternehmensdaten
const companyRecordId = $('Search records').first()?.json?.id || null;

// Schritt 6: Formatiere den EINEN Cluster
const clusterId = `CLUSTER-${Date.now()}`;

const keywordsText = Array.isArray(clusterData.secondary_keywords)
  ? clusterData.secondary_keywords.join(', ')
  : clusterData.secondary_keywords;

return [{
  json: {
    cluster_id: clusterId,
    cluster_name: clusterData.cluster_name,
    primary_keyword: clusterData.primary_keyword,
    secondary_keywords: keywordsText,
    blog_potential: clusterData.blog_potential || 'high',
    target_word_count: clusterData.target_word_count || 3500,
    company_record_id: companyRecordId,
    cluster_size: (clusterData.secondary_keywords?.length || 0) + 1,
    created_at: new Date().toISOString()
  }
}];

// Hole LLM Output von der Set Node (jetzt: output_gliederung!)
