const existingBlogs = $input.all();

// Sammle alle Haupt-Keywords und Titel
const usedTopics = existingBlogs
  .map(blog => {
    // In n8n ist die Struktur: blog.json (nicht blog.json.fields!)
    const keyword = blog.json['Haupt-Keyword'];
    const titel = blog.json.Titel;
    return [keyword, titel].filter(Boolean);
  })
  .flat()
  .join(', ');

// Wenn keine Blogs existieren
const exclusionText = usedTopics.length > 0 
  ? `⚠️ WICHTIG: Wähle ein NEUES Thema. Diese Themen wurden bereits behandelt: ${usedTopics}`
  : '';

return [{
  json: {
    exclusion_list: exclusionText,
    anzahl_blogs: existingBlogs.length
  }
}];

// Hole den Titel direkt aus Search records3
const titel = $input.first().json.Titel || 'Unbekannt';

// Hole die Bild Prompts
const bildPromptsRaw = $input.first().json['Bild Prompts'].value;

// Parse JSON
let prompts;
try {
  prompts = JSON.parse(bildPromptsRaw);
} catch (error) {
  throw new Error(`JSON Parse Error: ${error.message}`);
}

// Hole Record-ID
const recordId = $input.first().json.id;

// Erstelle 7 separate Items (für Loop!)
const promptArray = [
  { type: 'Header', prompt: prompts.header, index: 1, sort: 'header' },
  { type: 'Section 1', prompt: prompts.section_1, index: 2, sort: 'section-1' },
  { type: 'Section 2', prompt: prompts.section_2, index: 3, sort: 'section-2' },
  { type: 'Section 3', prompt: prompts.section_3, index: 4, sort: 'section-3' },
  { type: 'Section 4', prompt: prompts.section_4, index: 5, sort: 'section-4' },
  { type: 'Section 5', prompt: prompts.section_5, index: 6, sort: 'section-5' },
  { type: 'Fazit', prompt: prompts.fazit, index: 7, sort: 'fazit' }
];

// Gib 7 Items zurück mit Titel in jedem Item!
return promptArray.map(item => ({
  json: {
    blog_record_id: recordId,
    blog_titel: titel,                    // ← Titel aus Search records3!
    medientitel: `${item.type} - ${titel}`,
    typ: item.type,
    prompt: item.prompt,
    index: item.index,
    sort: item.sort
  }
}));

// Hole Binary Data
const binaryData = $input.item.binary.data;

// Hole medientitel direkt von "Bild-Prompts aufteilen" Node
const medientitel = $('Bild-Prompts aufteilen').item.json.medientitel;

// Bereinige für Dateinamen
const cleanFileName = medientitel
  .replace(/\s+/g, '-')
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/Ä/g, 'Ae')
  .replace(/Ö/g, 'Oe')
  .replace(/Ü/g, 'Ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-zA-Z0-9-]/g, '')
  .substring(0, 80);

const newFileName = `${cleanFileName}.png`;

// Return
return {
  json: $input.item.json,
  binary: {
    data: {
      ...binaryData,
      fileName: newFileName
    }
  }
};
